/** @odoo-module **/

import { registry } from "@web/core/registry";
import { rpc } from "@web/core/network/rpc";

console.log(">> CUSTOM TABLE ACTIONS: Script Loaded with Debug Logs <<");

window.__tableActionStorage = window.__tableActionStorage || { activeRow: null };

/* Capture clicked table row */
document.addEventListener(
    "mousedown",
    function (e) {
        const clickedRow = e.target.closest("tr");
        if (clickedRow) {
            window.__tableActionStorage.activeRow = clickedRow;
            console.log("DEBUG: Row captured on mousedown.");
        }
    },
    true
);

/* Wait for context menu to appear */
document.addEventListener(
    "mousedown",
    function () {
        setTimeout(() => {
            injectCreateActivityOption();
        }, 250);
    },
    true
);

function injectCreateActivityOption() {
    /* Only on forms that expose the HTML-table opportunity anchor; avoids injecting
       into unrelated menus (e.g. hr.applicant Kanban has "Delete" but no table row / opp id). */
    if (!document.querySelector("[name='opp_id_raw']")) {
        return;
    }

    const allMenus = document.querySelectorAll(
        ".dropdown-menu.show, .o_popover, .popover, [role='menu']"
    );

    allMenus.forEach((menu) => {
        if (menu.querySelector(".o_create_activity_row")) return;
        /* Kanban record menus are not HTML-field table row menus */
        if (menu.closest(".o_kanban_record")) {
            return;
        }

        const menuText = menu.innerText || "";
        if (
            !menuText.includes("Delete") &&
            !menuText.includes("Row") &&
            !menuText.includes("Insert")
        ) {
            return;
        }

        const item = document.createElement("a");
        item.className = "dropdown-item o_create_activity_row";
        item.style.cssText =
            "display:flex;align-items:center;padding:10px;color:#714B67;font-weight:bold;cursor:pointer;border-bottom:1px solid #eee;";
        item.innerHTML =
            '<i class="fa fa-clock-o me-2"></i> Create Activity';

        item.addEventListener("mousedown", function (ev) {
            ev.preventDefault();
            ev.stopPropagation();
            console.log("DEBUG: 'Create Activity' menu item clicked.");
            handleCreateActivity();
        });

        menu.prepend(item);
    });
}

async function handleCreateActivity() {
    const activeRow = window.__tableActionStorage.activeRow;
    if (!activeRow) return;

    // 1. Get the Parent ID from your Anchor (ID: 1)
    const oppIdAnchor = document.querySelector("[name='opp_id_raw'] span, [name='opp_id_raw'] div");
    const parentOppId = oppIdAnchor ? parseInt(oppIdAnchor.innerText.trim(), 10) : null;

    if (!parentOppId) {
        alert("Action Failed: Opportunity ID not found.");
        return;
    }

    // 2. Scrape the row data
    const cells = Array.from(activeRow.querySelectorAll("td, th"));
    const rowContent = cells.map(c => c.innerText.trim()).filter(t => t).join(" | ");
    const htmlNote = `<p><strong>Source Note:</strong> ${rowContent}</p>`;

    try {
        // 3. The RPC call (This part is confirmed working)
        const action = await rpc("/web/dataset/call_kw", {
            model: "business.opportunity",
            method: "action_create_activity_from_content",
            args: [parentOppId, htmlNote],
            kwargs: {},
        });

        if (action) {
            // 4. THE ODOO 18 UI HOOK
            // We search the UI for the Action Service instance
            const actionService = registry.category("services").get("action");

            // Try different ways to execute the action without refreshing
            if (actionService && typeof actionService.doAction === 'function') {
                actionService.doAction(action);
            } else {
                // ULTIMATE FALLBACK: Use the Owl App Env directly
                const owlApp = Object.values(document.querySelector('.o_web_client') || {})
                                     .find(v => v?.__owl__)?.__owl__?.app;
                if (owlApp?.env?.services?.action) {
                    owlApp.env.services.action.doAction(action);
                } else {
                    // Final attempt: Global Odoo object
                    window.odoo.__WOWL_DEBUG__.root.env.services.action.doAction(action);
                }
            }
            console.log("LL SUCCESS: Activity window requested.");
        }
    } catch (err) {
        console.error("LL RPC FAILED:", err);
        alert("Connection Error: Could not create activity.");
    }
}

